import { createRequire } from 'node:module'
import { join } from 'path'

import { sveltekit } from '@sveltejs/kit/vite'
import { build as esbuildBundle } from 'esbuild'
import UnpluginAutoImport from 'unplugin-auto-import/vite'
import { FileSystemIconLoader } from 'unplugin-icons/loaders'
import IconsResolver from 'unplugin-icons/resolver'
import Icons from 'unplugin-icons/vite'
import { defineConfig, type Plugin } from 'vite'

import { scalarResolver } from './vite-plugin-scalar-resolver'

/**
 * Vite plugin to bundle the cody-web agent worker into a single self-contained static asset.
 *
 * The dist/agent.worker.js from @sourcegraph/cody-web is a split bundle that imports
 * other chunk files (e.g. ./agent.worker-*.mjs). When used with ?worker, Vite would
 * re-bundle and re-minify these, which breaks the vscode-jsonrpc transport in Safari
 * ("Maximum call stack exceeded").
 *
 * We use esbuild to produce a single self-contained bundle with minify:false, then emit
 * it as a static asset served at a regular HTTP URL (not a blob: URL). This fixes two
 * problems at once:
 *   1. No minification → Safari vscode-jsonrpc stack overflow is avoided.
 *   2. Regular HTTP URL → Playwright's page.route() can intercept the worker's requests
 *      in integration tests (blob: URL workers bypass Playwright's network interception).
 *
 * Mirrors the fix in client/build-config/src/esbuild/workerPlugin.ts.
 */
function codyWebWorkerPlugin(): Plugin {
    const VIRTUAL_ID = '\0cody-web-agent-worker'
    return {
        name: 'cody-web-worker',
        enforce: 'pre',
        apply: 'build',
        resolveId(id) {
            if (id.includes('@sourcegraph/cody-web') && id.includes('agent.worker')) {
                return VIRTUAL_ID
            }
        },
        async load(id) {
            if (id !== VIRTUAL_ID) {
                return
            }
            const require = createRequire(import.meta.url)
            const workerEntryPath = require.resolve('@sourcegraph/cody-web/dist/agent.worker.js')

            // Re-bundle all worker chunks (agent.worker.js + its split imports) into a
            // single self-contained file. minify:false prevents the vscode-jsonrpc transport
            // from causing "Maximum call stack exceeded" in Safari.
            const result = await esbuildBundle({
                entryPoints: [workerEntryPath],
                bundle: true,
                write: false,
                format: 'esm',
                minify: false,
                platform: 'browser',
            })
            const workerCode = result.outputFiles[0].text

            // Emit as a static asset so it's served at a regular HTTP URL.
            // Unlike blob: URLs, HTTP URL workers have their requests properly intercepted
            // by Playwright's page.route() in integration tests.
            const fileId = this.emitFile({
                type: 'asset',
                name: 'agent.worker.js',
                source: workerCode,
            })

            return `
                const workerUrl = new URL(import.meta.ROLLUP_FILE_URL_${fileId}, import.meta.url)
                export default class CodyAgentWorker extends globalThis.Worker {
                    constructor() { super(workerUrl, { type: 'module' }); }
                }
            `
        },
    }
}

export function AutoImport(update: boolean): Plugin | Plugin[] {
    return UnpluginAutoImport({
        // Ignore TS when running Bazel. It would try to write to the file which is not
        // possible in bazel.
        dts: update ? './src/auto-imports.d.ts' : false,
        resolvers: [
            IconsResolver({
                prefix: 'i',
                customCollections: ['sg', 'symbol'],
            }),
        ],
        include: [/\/node_modules\//, /\.(svelte|ts)$/],
        exclude: [/\/\.git\//],
    })
}

/**
 * Vite plugin to handle .yaml file imports and return their raw content as default export.
 */
function yamlLoader(): Plugin {
    return {
        name: 'yaml-loader',
        transform(code, id) {
            if (id.endsWith('.yaml') || id.endsWith('.yml')) {
                // Return it as a default export with the raw content
                return `export default ${JSON.stringify(code)}`
            }
        },
    }
}

export default defineConfig(({ mode }) => ({
    plugins: [
        scalarResolver(),
        sveltekit(),
        codyWebWorkerPlugin(),
        Icons({
            compiler: 'svelte',
            customCollections: {
                sg: FileSystemIconLoader('./assets/icons'),
                symbol: FileSystemIconLoader('./assets/symbol-icons'),
            },
        }),
        yamlLoader(),
    ],

    build: {
        target: 'es2022',
        // Enabling sourcemap makes build process fail with out-of-memory error
        sourcemap: false,
    },

    define:
        mode === 'test'
            ? {}
            : {
                  'process.platform': '"browser"',
                  'process.env.VITEST': 'null',
                  'process.env.NODE_ENV': `"${mode}"`,
                  'process.env.SOURCEGRAPH_API_URL': JSON.stringify(process.env.SOURCEGRAPH_API_URL),
                  'process.env.DEV_ENABLE_WORKSPACE_SETUP': JSON.stringify(process.env.DEV_ENABLE_WORKSPACE_SETUP),
                  'process.env': '{}',
              },

    css: {
        preprocessorOptions: {
            scss: {
                loadPaths: [
                    // Our scss files and scss files in client/* often import global styles via @import 'wildcard/src/...'
                    // Adding '..' as load path causes scss to look for these imports in the client folder.
                    // (without it scss @import paths are always relative to the importing file)
                    join(__dirname, '..'),
                ],
                additionalData: "@use 'uikit/src/lib/styles/breakpoints.scss' as *;",
                verbose: true,
            },
        },
        modules: {
            localsConvention: 'camelCase',
        },
    },

    resolve: {
        alias: [
            // We generate corresponding .gql.ts files for .gql files.
            // This alias allows us to import .gql files and have them resolved to the generated .gql.ts files.
            {
                find: /^(.*)\.gql$/,
                replacement: '$1.gql.ts',
            },
            // We import the path module in browser code, which is not available in the browser.
            // Replace it with the path-browserify module.
            {
                find: 'path',
                replacement: 'path-browserify',
            },
        ],
    },

    worker: {
        format: 'es',
    },

    optimizeDeps: {
        exclude: ['linguist-languages'],
    },

    esbuild: {
        jsx: 'automatic',
    },

    ssr: {
        optimizeDeps: {
            include: [
                // path-browserify is imported due to aliasing the path module in browser code.
                // That means Vite doesn"t know beforehand that this module is used. We have to
                // explicitly include it here to make it work in the dev build since it's a CommonJS module.
                'path-browserify',
            ],
            exclude: ['linguist-languages'],
        },
        noExternal: [
            // Due to aliasing SvelteKit tries to import `path-browserify` during the build as part of loading
            // the server-side code. This causes an error because `path-browserify` is a CommonJS module.
            // By adding it to `noExternal` we tell Vite to process it and convert it to an ES module.
            'path-browserify',
        ],
    },
}))

