/**
 * Tests for @-mention anchor position detection in the PromptEditor plugins.
 *
 * These tests verify that mention positions are derived directly from ProseMirror
 * state rather than a flattened string, ensuring correct behavior across
 * single-line and multi-paragraph content.
 */

import { schema as basicSchema } from 'prosemirror-schema-basic'
import { EditorState, TextSelection } from 'prosemirror-state'
import { describe, expect, test } from 'vitest'

import { mentionKey, mentionPlugin } from './PromptEditor.plugins'

/**
 * Creates an EditorState with a single paragraph containing the given text,
 * with the cursor placed at the given offset within the paragraph content.
 */
function singleParagraphState(text: string, cursorOffset: number): EditorState {
    const paraNode = basicSchema.node('paragraph', null, text ? [basicSchema.text(text)] : [])
    const doc = basicSchema.node('doc', null, [paraNode])
    // PM position: 0 = before para open, 1 = first char in para
    const cursorPos = 1 + cursorOffset
    const state = EditorState.create({
        doc,
        selection: TextSelection.create(doc, cursorPos),
        plugins: [mentionPlugin({ onChange: () => {} })],
    })
    // Apply identity transaction to trigger plugin's apply()
    return state.apply(state.tr)
}

/**
 * Creates an EditorState with multiple paragraphs, placing the cursor
 * at `cursorOffset` characters into the paragraph at `cursorPara` (0-indexed).
 */
function multiParagraphState(paragraphs: string[], cursorPara: number, cursorOffset: number): EditorState {
    const paraNodes = paragraphs.map(text =>
        basicSchema.node('paragraph', null, text ? [basicSchema.text(text)] : [])
    )
    const doc = basicSchema.node('doc', null, paraNodes)

    // Calculate absolute PM cursor position:
    // Each paragraph has nodeSize = 2 + text.length (1 for open + 1 for close)
    let paraStart = 0
    for (let i = 0; i < cursorPara; i++) {
        paraStart += paraNodes[i].nodeSize
    }
    // paraStart is now the position before the paragraph's open token;
    // +1 moves inside the paragraph, then +cursorOffset reaches the desired char.
    const cursorPos = paraStart + 1 + cursorOffset

    const state = EditorState.create({
        doc,
        selection: TextSelection.create(doc, cursorPos),
        plugins: [mentionPlugin({ onChange: () => {} })],
    })
    return state.apply(state.tr)
}

describe('mentionPlugin anchor detection', () => {
    describe('single-line scenarios', () => {
        test('detects @ mention mid-sentence', () => {
            // "hello @world" — cursor after 'd'
            const state = singleParagraphState('hello @world', 12)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('world')
            // '@' is the 7th character (1-indexed), PM pos inside a single para = 1 + 6 = 7
            expect(mention?.from).toBe(7)
            // cursor is after 'd', PM pos = 1 + 12 = 13
            expect(mention?.to).toBe(13)
        })

        test('detects @ at start of content', () => {
            // "@repo" — cursor after 'o'
            const state = singleParagraphState('@repo', 5)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('repo')
            expect(mention?.from).toBe(1) // '@' is the first char, PM pos 1
            expect(mention?.to).toBe(6)
        })

        test('detects @ after whitespace', () => {
            // "search @file" — cursor after 'e'
            const state = singleParagraphState('search @file', 12)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('file')
            expect(mention?.from).toBe(8) // '@' at index 7, PM pos = 1 + 7 = 8
            expect(mention?.to).toBe(13)
        })

        test('detects @ with partial query (cursor in middle of query)', () => {
            // "hello @wor" — cursor after 'r' (mid-query)
            const state = singleParagraphState('hello @wor', 10)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('wor')
            expect(mention?.from).toBe(7)
            expect(mention?.to).toBe(11)
        })

        test('returns null when no @ present', () => {
            const state = singleParagraphState('hello world', 11)
            const mention = mentionKey.getState(state)
            expect(mention).toBeNull()
        })

        test('returns null for empty content', () => {
            const state = singleParagraphState('', 0)
            const mention = mentionKey.getState(state)
            expect(mention).toBeNull()
        })
    })

    describe('multi-paragraph scenarios', () => {
        test('detects @ at start of second paragraph', () => {
            // Para 1: "hello" (nodeSize=7), Para 2: "@world"
            // Para 2 starts at PM pos 7; '@' is first char at PM pos 8
            const state = multiParagraphState(['hello', '@world'], 1, 6)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('world')
            // '@' is first char of para 2: blockStart = 8, atIdx = 0 → from = 8
            expect(mention?.from).toBe(8)
            // cursor after 'd': blockStart(8) + 6 = 14
            expect(mention?.to).toBe(14)
        })

        test('detects @ in second paragraph after other text', () => {
            // Para 1: "line one" (nodeSize=10), Para 2: "find @repo"
            // Para 2 blockStart = 11; '@' at index 5 → from = 16
            const state = multiParagraphState(['line one', 'find @repo'], 1, 10)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('repo')
            expect(mention?.from).toBe(16) // 11 + 5
            expect(mention?.to).toBe(21) // 11 + 10
        })

        test('detects @ in third paragraph', () => {
            // Para 1: "a" (nodeSize=3), Para 2: "b" (nodeSize=3), Para 3: "@c"
            // Para 3 starts at PM pos 3+3=6; blockStart = 7; '@' at idx 0 → from = 7
            const state = multiParagraphState(['a', 'b', '@c'], 2, 2)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('c')
            expect(mention?.from).toBe(7) // blockStart of para3 = 7
            expect(mention?.to).toBe(9)
        })

        test('returns null when cursor is in first paragraph without @', () => {
            const state = multiParagraphState(['hello', '@world'], 0, 5)
            const mention = mentionKey.getState(state)
            expect(mention).toBeNull()
        })

        test('does not detect @ from previous paragraph when cursor is at start of new paragraph', () => {
            // Para 1: "@mention", Para 2: "" — cursor at start of empty para 2
            // The '@' is in para 1 and should NOT be detected when cursor is in para 2
            const state = multiParagraphState(['@mention', ''], 1, 0)
            const mention = mentionKey.getState(state)
            expect(mention).toBeNull()
        })
    })

    describe('edge cases', () => {
        test('detects @ immediately before cursor (empty query)', () => {
            // "@" — cursor immediately after @
            const state = singleParagraphState('@', 1)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('')
            expect(mention?.from).toBe(1)
            expect(mention?.to).toBe(2)
        })

        test('detects @ at start of second paragraph with empty query', () => {
            // Para 1: "text", Para 2: "@" — cursor after @
            const state = multiParagraphState(['text', '@'], 1, 1)
            const mention = mentionKey.getState(state)

            expect(mention).not.toBeNull()
            expect(mention?.query).toBe('')
            // Para 1 nodeSize=6, para 2 blockStart=7
            expect(mention?.from).toBe(7)
            expect(mention?.to).toBe(8)
        })

        test('returns null for non-empty selection (range selection)', () => {
            // Range selection should never trigger mention
            const text = 'hello @world'
            const paraNode = basicSchema.node('paragraph', null, [basicSchema.text(text)])
            const doc = basicSchema.node('doc', null, [paraNode])
            // Create a non-empty selection (anchor != head)
            const selection = TextSelection.create(doc, 7, 13)
            const state = EditorState.create({
                doc,
                selection,
                plugins: [mentionPlugin({ onChange: () => {} })],
            }).apply(EditorState.create({ doc, selection, plugins: [mentionPlugin({ onChange: () => {} })] }).tr)
            const mention = mentionKey.getState(state)
            expect(mention).toBeNull()
        })
    })
})

