// Simple test to verify the fix logic
// Using the prosemirror libraries from the workspace

import { createRequire } from 'module'
const require = createRequire(import.meta.url)

// Load prosemirror from workspace node_modules
process.env.NODE_PATH = '/workspace/node_modules'
require('module').Module._initPaths()

// Try to load prosemirror packages
let schema, EditorState, TextSelection, Plugin, PluginKey

try {
    const pmState = require('/workspace/client/web-sveltekit/node_modules/prosemirror-state')
    const pmSchemaBasic = require('/workspace/client/web-sveltekit/node_modules/prosemirror-schema-basic')

    EditorState = pmState.EditorState
    TextSelection = pmState.TextSelection
    Plugin = pmState.Plugin
    PluginKey = pmState.PluginKey
    schema = pmSchemaBasic.schema

    console.log('Loaded prosemirror packages successfully')
} catch (e) {
    console.error('Failed to load prosemirror:', e.message)
    process.exit(1)
}

// Replicate the FIXED logic
function detectMentionAtCursor(text, cursorPos) {
    let atPos = -1
    for (let i = cursorPos - 1; i >= 0; i--) {
        if (text[i] === '@') {
            atPos = i
            break
        }
        if (text[i] === '\n') {
            break
        }
    }
    if (atPos >= 0) {
        const afterAt = text.slice(atPos + 1, cursorPos)
        if (!afterAt.includes('\n')) {
            return { atPos, query: afterAt }
        }
    }
    return null
}

const mentionKey = new PluginKey('mention')

function mentionPlugin(opts) {
    return new Plugin({
        key: mentionKey,
        state: {
            init: () => null,
            apply(tr, prev, _oldState, newState) {
                const sel = newState.selection
                if (!sel.empty) return null

                const $cursor = sel.$from
                const blockStart = $cursor.start()
                if (sel.from <= blockStart) return null

                const blockText = newState.doc.textBetween(blockStart, sel.from, '\n')
                const result = detectMentionAtCursor(blockText, blockText.length)

                if (!result) return null

                return {
                    active: true,
                    from: blockStart + result.atPos,
                    to: sel.from,
                    query: result.query,
                }
            },
        },
    })
}

function createState(doc, cursorPos) {
    const state = EditorState.create({
        doc,
        selection: TextSelection.create(doc, cursorPos),
        plugins: [mentionPlugin({ onChange: () => {} })],
    })
    return state.apply(state.tr)
}

let passed = 0
let failed = 0

function test(name, fn) {
    try {
        fn()
        console.log(`  ✓ ${name}`)
        passed++
    } catch (e) {
        console.log(`  ✗ ${name}: ${e.message}`)
        failed++
    }
}

function expect(val) {
    return {
        toBe: (expected) => {
            if (val !== expected) throw new Error(`Expected ${JSON.stringify(expected)} but got ${JSON.stringify(val)}`)
        },
        toBeNull: () => {
            if (val !== null) throw new Error(`Expected null but got ${JSON.stringify(val)}`)
        },
        not: {
            toBeNull: () => {
                if (val === null) throw new Error(`Expected non-null but got null`)
            }
        }
    }
}

console.log('\nSingle-paragraph tests:')

test('detects @ mention mid-sentence', () => {
    const text = 'hello @world'
    const doc = schema.node('doc', null, [schema.node('paragraph', null, [schema.text(text)])])
    const state = createState(doc, 1 + 12) // after 'd'
    const mention = mentionKey.getState(state)

    expect(mention).not.toBeNull()
    expect(mention.query).toBe('world')
    expect(mention.from).toBe(7) // '@' at PM pos 7 (para opens at 0, '@' is 7th char)
    expect(mention.to).toBe(13)
})

test('detects @ at start of content', () => {
    const text = '@repo'
    const doc = schema.node('doc', null, [schema.node('paragraph', null, [schema.text(text)])])
    const state = createState(doc, 1 + 5) // after 'o'
    const mention = mentionKey.getState(state)

    expect(mention).not.toBeNull()
    expect(mention.query).toBe('repo')
    expect(mention.from).toBe(1) // '@' at PM pos 1
    expect(mention.to).toBe(6)
})

test('returns null when no @ present', () => {
    const text = 'hello world'
    const doc = schema.node('doc', null, [schema.node('paragraph', null, [schema.text(text)])])
    const state = createState(doc, 1 + 11)
    const mention = mentionKey.getState(state)
    expect(mention).toBeNull()
})

console.log('\nMulti-paragraph tests:')

test('detects @ at start of second paragraph', () => {
    // Para 1: "hello" (nodeSize=7), Para 2: "@world" (nodeSize=8)
    // Para 2 blockStart = 8 (para1 nodeSize=7, para2 opens at 7, first content at 8)
    const para1 = schema.node('paragraph', null, [schema.text('hello')])
    const para2 = schema.node('paragraph', null, [schema.text('@world')])
    const doc = schema.node('doc', null, [para1, para2])

    // PM pos: para1 size=7, para2 starts at 7, content at 8
    // Cursor after 'd' in "@world": 8 + 6 = 14
    const state = createState(doc, 14)
    const mention = mentionKey.getState(state)

    expect(mention).not.toBeNull()
    expect(mention.query).toBe('world')
    expect(mention.from).toBe(8) // '@' at PM pos 8
    expect(mention.to).toBe(14)
})

test('OLD (buggy) code would give wrong position - verifying fix', () => {
    // Para 1: "hello" (nodeSize=7), Para 2: "@world" (nodeSize=8)
    // blockStart = 8, '@' at index 0 → from = 8 (CORRECT with fix)
    // OLD code: flat text "hello\n@world", atPos=6, from = 6+1 = 7 (WRONG! PM pos 7 is between blocks)
    const para1 = schema.node('paragraph', null, [schema.text('hello')])
    const para2 = schema.node('paragraph', null, [schema.text('@world')])
    const doc = schema.node('doc', null, [para1, para2])

    const state = createState(doc, 14)
    const mention = mentionKey.getState(state)

    // With the fix, from should be 8 (not 7 as the old code would give)
    expect(mention.from).toBe(8)
    expect(mention.from !== 7).toBe(true) // NOT the old buggy value
})

test('does not detect @ from previous paragraph', () => {
    // Para 1: "@mention", Para 2: "" — cursor at start of empty para 2
    const para1 = schema.node('paragraph', null, [schema.text('@mention')])
    const para2 = schema.node('paragraph', null, [])
    const doc = schema.node('doc', null, [para1, para2])

    // para1 size = 10, para2 starts at 10, content at 11, cursor at 11 (empty)
    const state = createState(doc, 11)
    const mention = mentionKey.getState(state)
    expect(mention).toBeNull()
})

test('detects @ in third paragraph', () => {
    const para1 = schema.node('paragraph', null, [schema.text('a')]) // nodeSize=3
    const para2 = schema.node('paragraph', null, [schema.text('b')]) // nodeSize=3
    const para3 = schema.node('paragraph', null, [schema.text('@c')]) // nodeSize=4
    const doc = schema.node('doc', null, [para1, para2, para3])

    // para3 starts at 3+3=6, content at 7; cursor after 'c' = 7+2=9
    const state = createState(doc, 9)
    const mention = mentionKey.getState(state)

    expect(mention).not.toBeNull()
    expect(mention.query).toBe('c')
    expect(mention.from).toBe(7) // blockStart of para3 = 7
    expect(mention.to).toBe(9)
})

console.log('\nEdge cases:')

test('detects @ immediately before cursor (empty query)', () => {
    const doc = schema.node('doc', null, [schema.node('paragraph', null, [schema.text('@')])])
    const state = createState(doc, 2) // cursor after '@'
    const mention = mentionKey.getState(state)

    expect(mention).not.toBeNull()
    expect(mention.query).toBe('')
    expect(mention.from).toBe(1)
    expect(mention.to).toBe(2)
})

console.log(`\nResults: ${passed} passed, ${failed} failed`)
if (failed > 0) process.exit(1)
