import { existsSync, readFileSync } from 'fs'
import path from 'path'

import { load } from 'js-yaml'

interface PnpmWorkspaceFile {
    packages: string[]
}

function fromPnpmWorkspaceFile(filePath: string): string[] {
    const root = path.dirname(filePath)
    const packages = (load(readFileSync(filePath, 'utf8')) as PnpmWorkspaceFile).packages
    return packages
        .filter(p => !p.startsWith('!') && !p.includes('*')) // skip negations and globs
        .map(p => `${p}/vitest.config.ts`)
        .filter(p => existsSync(path.join(root, p)))
        .concat(['client/*/vitest.config.ts']) // glob for client packages
}

export default fromPnpmWorkspaceFile(path.join(__dirname, 'pnpm-workspace.yaml'))

