arguments.new_string:
import { accessSync, constants, existsSync, readFileSync } from 'fs'
import path from 'path'

import { load } from 'js-yaml'

interface PnpmWorkspaceFile {
    packages: string[]
}

function isWritableDir(dirPath: string): boolean {
    try {
        accessSync(dirPath, constants.W_OK)
        return true
    } catch {
        return false
    }
}

function fromPnpmWorkspaceFile(filePath: string): string[] {
    const root = path.dirname(filePath)
    const packages = (load(readFileSync(filePath, 'utf8')) as PnpmWorkspaceFile).packages
    // Only include packages whose vitest.config.ts exists AND whose directory is writable
    // (writable dirs means vite can create .timestamp.mjs files needed to compile TS configs)
    return packages
        .filter(p => !p.startsWith('!') && !p.includes('*')) // skip negations and globs
        .map(p => `${p}/vitest.config.ts`)
        .filter(p => {
            const fullPath = path.join(root, p)
            return existsSync(fullPath) && isWritableDir(path.dirname(fullPath))
        })
        .concat(['client/*/vitest.config.ts']) // glob for client packages with existing writable configs
}

export default fromPnpmWorkspaceFile(path.join(__dirname, 'pnpm-workspace.yaml'))

