import { accessSync, constants, existsSync, readdirSync, readFileSync } from 'fs'
import path from 'path'

import { load } from 'js-yaml'

interface PnpmWorkspaceFile {
    packages: string[]
}

function isWritableDir(dirPath: string): boolean {
    try {
        accessSync(dirPath, constants.W_OK)
        return true
    } catch {
        return false
    }
}

function fromPnpmWorkspaceFile(filePath: string): string[] {
    const root = path.dirname(filePath)
    // Find all vitest.config.ts files in writable package directories under client/*
    const clientDir = path.join(root, 'client')
    const writableConfigs: string[] = []
    try {
        for (const pkg of readdirSync(clientDir)) {
            const configPath = path.join(clientDir, pkg, 'vitest.config.ts')
            if (existsSync(configPath) && isWritableDir(path.join(clientDir, pkg))) {
                writableConfigs.push(`client/${pkg}/vitest.config.ts`)
            }
        }
    } catch {
        // ignore errors
    }
    return writableConfigs
}

export default fromPnpmWorkspaceFile(path.join(__dirname, 'pnpm-workspace.yaml'))

